static Graph make_dag() {
    Graph g(GraphType::Directed);
    for (int i = 0; i < 6; i++) g.add_node_with_id(i);
    g.add_edge(0, 1); g.add_edge(0, 2);
    g.add_edge(1, 3); g.add_edge(2, 3);
    g.add_edge(3, 4); g.add_edge(4, 5);
