    Graph g(GraphType::Directed);
    for (int i = 0; i < 7; i++) g.add_node_with_id(i);
    g.add_edge(0, 1); g.add_edge(0, 2);
    g.add_edge(1, 3); g.add_edge(1, 4);
    g.add_edge(2, 5); g.add_edge(2, 6);
    return g;
}

